    EditorOnlySessionEnvironmentAllowList:[]session_environment = array{};

    MeshComponent&lt;protected&gt;:castable_subtype((/Verse.org:)SceneGraph.mesh_component) = (/Verse.org:)SceneGraph.mesh_component;

    GetBounds&lt;public&gt;():vector3;

